ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN StocksLendingStatusID COMMENT 'StocksLendingStatusID projected from BI_DB_MarketingCloudDaily (see base table wiki). Stocks lending consent status. Only populated where StocksLendingStatusID=1 (opted in) from Ext_Dim_Customer_StocksLending via Dim_Customer GCID join. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN StocksLendingOptInDate COMMENT 'StocksLendingOptInDate projected from BI_DB_MarketingCloudDaily (see base table wiki). Date of stocks lending opt-in consent. From Ext_Dim_Customer_StocksLending.ConsentDateTime where StocksLendingStatusID=1. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN eTM_IBAN_Type COMMENT 'eTM_IBAN_Type projected from BI_DB_MarketingCloudDaily (see base table wiki). IBAN country code prefix (first 2 characters of BankAccountIBAN). From eMoney_Dim_Account where IsValidETM=1 AND GCID_Unique_Count=1. E.g., MT, DE, GB. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN eTM_AccountName_LocalCurrency COMMENT 'eTM_AccountName_LocalCurrency projected from BI_DB_MarketingCloudDaily (see base table wiki). eMoney account local currency description. From eMoney_Dim_Account.CurrencyBalanceISODesc. E.g., EUR, GBP. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Cluster COMMENT 'Cluster projected from BI_DB_MarketingCloudDaily (see base table wiki). Customer behavioral cluster assignment. From BI_DB_CID_DailyCluster.ClusterDetail. 6 values: Crypto, Equities Investors, Equities Crypto, Equities Traders, Leveraged Traders, Diversified Traders. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN ClusterDate COMMENT 'ClusterDate projected from BI_DB_MarketingCloudDaily (see base table wiki). Date of the cluster assignment. From BI_DB_CID_DailyCluster.FromDate. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN PositionOpen_LastDate_ETF COMMENT 'PositionOpen_LastDate_ETF projected from BI_DB_MarketingCloudDaily (see base table wiki). Date of the last ETF position opened by this customer. MAX(Dim_Position.OpenOccurred) where Dim_Instrument.InstrumentTypeID=6, MirrorID=0 (non-copy), IsPartialCloseChild=0, IsAirDrop=0. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Rewarded_LastMonth_eMoney COMMENT 'Rewarded_LastMonth_eMoney projected from BI_DB_MarketingCloudDaily (see base table wiki). Month reference for the eMoney card cashback calculation. DATEFROMPARTS of prior month. Only updated on the 1st of each month. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Monthly_CardSpent_eMoney COMMENT 'Monthly_CardSpent_eMoney projected from BI_DB_MarketingCloudDaily (see base table wiki). Total card spend for the prior month (HolderAmount * -1). Only updated on the 1st of each month. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Monthly_RewardedChashBack_eMoney COMMENT 'Monthly_RewardedChashBack_eMoney projected from BI_DB_MarketingCloudDaily (see base table wiki). Cashback amount rewarded for the prior month. 4% of eligible spend, capped at 1500. Only updated on the 1st of each month. Note: column name typo ("Chash" instead of "Cash"). (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Monthly_CardEligibleCashBack_eMoney COMMENT 'Monthly_CardEligibleCashBack_eMoney projected from BI_DB_MarketingCloudDaily (see base table wiki). Eligible card spend for cashback (excludes gambling/crypto/money transfer MCCs). Only updated on the 1st of each month. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN FirstDepositDateGlobal COMMENT 'FirstDepositDateGlobal projected from BI_DB_MarketingCloudDaily (see base table wiki). First deposit date across all platforms (trading + IBAN). From Function_MIMO_First_Deposit_All_Platforms(1). Only populated for CIDs whose first deposit was on @date. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN DepositsUSD_Global COMMENT 'DepositsUSD_Global projected from BI_DB_MarketingCloudDaily (see base table wiki). Cumulative deposit amount in USD across all platforms. SUM(AmountUSD) from DDR_Fact_MIMO_AllPlatforms where MIMOAction=''Deposit'' AND IsInternalTransfer=0. Updated for CIDs with a deposit on @date. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN BalanceGlobal COMMENT 'BalanceGlobal projected from BI_DB_MarketingCloudDaily (see base table wiki). Global balance = CreditTP + IBANBalance from DDR_Fact_AUM at @dateID. Combines trading platform and eMoney balances. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN EquityGlobal COMMENT 'EquityGlobal projected from BI_DB_MarketingCloudDaily (see base table wiki). Global equity from DDR_Fact_AUM.EquityGlobal at @dateID. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Total_Deposit_USD COMMENT 'Total_Deposit_USD projected from BI_DB_MarketingCloudDaily (see base table wiki). Cumulative trading platform deposits in USD. SUM(AmountUSD) from DDR_Fact_MIMO_AllPlatforms where MIMOPlatform=''TradingPlatform''. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Total_Deposit_EUR COMMENT 'Total_Deposit_EUR projected from BI_DB_MarketingCloudDaily (see base table wiki). Cumulative eMoney deposits in EUR. SUM(AmountOrigCurrency) where MIMOPlatform=''eMoney'' AND CurrencyID=2. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Total_Deposit_GBP COMMENT 'Total_Deposit_GBP projected from BI_DB_MarketingCloudDaily (see base table wiki). Cumulative eMoney deposits in GBP. SUM(AmountOrigCurrency) where MIMOPlatform=''eMoney'' AND CurrencyID=3. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Current_Balance_USD COMMENT 'Current_Balance_USD projected from BI_DB_MarketingCloudDaily (see base table wiki). Current trading platform USD balance. From DDR_Fact_AUM.CreditTP at @dateID. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Current_Balance_EUR COMMENT 'Current_Balance_EUR projected from BI_DB_MarketingCloudDaily (see base table wiki). Current eMoney EUR balance. SUM(eMoneyClientBalance.ClosingBalanceBO) where CurrencyBalanceISOCode=978 AND GCID_Unique_Count=1. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Current_Balance_GBP COMMENT 'Current_Balance_GBP projected from BI_DB_MarketingCloudDaily (see base table wiki). Current eMoney GBP balance. SUM(eMoneyClientBalance.ClosingBalanceBO) where CurrencyBalanceISOCode=826 AND GCID_Unique_Count=1. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN LastTransactionDate COMMENT 'LastTransactionDate projected from BI_DB_MarketingCloudDaily (see base table wiki). Last settled eMoney card transaction date. MAX(eMoney_Panel_FirstDates.LastCardSettledTXDate) where IsValidETM=1. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN AcceptedTnCs_Date COMMENT 'AcceptedTnCs_Date projected from BI_DB_MarketingCloudDaily (see base table wiki). Date the customer accepted ISA Terms & Conditions. From BI_OUTPUT_Customer_External_Table_ISA. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN DIY_PortfolioCreatedDate COMMENT 'DIY_PortfolioCreatedDate projected from BI_DB_MarketingCloudDaily (see base table wiki). ISA execution-only (DIY) portfolio creation date. MAX(PortfolioCreatedDate) where ProductName_Code=''isa-execution-only''. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN DIY_FirstDepositDate COMMENT 'DIY_FirstDepositDate projected from BI_DB_MarketingCloudDaily (see base table wiki). First deposit date into the DIY ISA portfolio. MAX(PortfolioFirstDepositDate) where ProductName_Code=''isa-execution-only''. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Cash_PortfolioCreatedDate COMMENT 'Cash_PortfolioCreatedDate projected from BI_DB_MarketingCloudDaily (see base table wiki). ISA cash portfolio creation date. MAX(PortfolioCreatedDate) where ProductName_Code=''isa-cash''. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Cash_FirstDepositDate COMMENT 'Cash_FirstDepositDate projected from BI_DB_MarketingCloudDaily (see base table wiki). First deposit date into the cash ISA portfolio. MAX(PortfolioFirstDepositDate) where ProductName_Code=''isa-cash''. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Managed_PortfolioCreatedDate COMMENT 'Managed_PortfolioCreatedDate projected from BI_DB_MarketingCloudDaily (see base table wiki). ISA discretionary (managed) portfolio creation date. MAX(PortfolioCreatedDate) where ProductName_Code=''isa-discretionary''. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN Managed_FirstDepositDate COMMENT 'Managed_FirstDepositDate projected from BI_DB_MarketingCloudDaily (see base table wiki). First deposit date into the managed ISA portfolio. MAX(PortfolioFirstDepositDate) where ProductName_Code=''isa-discretionary''. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN IsDefunded_across_all_portfolios COMMENT 'IsDefunded_across_all_portfolios projected from BI_DB_MarketingCloudDaily (see base table wiki). Whether ALL of the customer''s ISA portfolios are defunded. 1=all defunded, 0=at least one funded. MIN(CASE WHEN PortfolioDefunded=1 THEN 1 ELSE 0 END) across all portfolios. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN RAF_Inviter COMMENT 'RAF_Inviter projected from BI_DB_MarketingCloudDaily (see base table wiki). GCID of the person who invited this customer via Refer-a-Friend. From BI_DB_RAF_Invitees_KPIs.Inviter -> Dim_Customer.GCID. Note: stored as decimal, not int. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN RAF_LastCashoutDate COMMENT 'RAF_LastCashoutDate projected from BI_DB_MarketingCloudDaily (see base table wiki). Last cashout date from the RAF program for this invitee. MAX(LastCashoutDate) from BI_DB_RAF_Invitees_KPIs. (Tier 2 - SP_MarketingCloudDaily)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN etr_y COMMENT 'Lakehouse partition column (year). UC Gold view adds partition keys to base table export. (Tier 2 - Gold export)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN etr_ym COMMENT 'Lakehouse partition column (year-month). (Tier 2 - Gold export)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_marketingclouddaily_v ALTER COLUMN etr_ymd COMMENT 'Lakehouse partition column (year-month-day). (Tier 2 - Gold export)';

